    const visitor = this.currentVisitors.find(v => v.npcId === npcId);
    if (visitor) {
      this.randomNpcManager.onNpcDialogueEnd(visitor.configId);
      // 从当前场景访客中移除
      this.currentVisitors = this.currentVisitors.filter(v => v.npcId !== npcId);
    }
  }

  // ========== 来访提示相关 ==========

