  BootScene,
  TitleScene,
  ShopScene,
  DialogueScene,
  MemoryScene,
  DayEndScene,
  CommissionListScene,
  QuestLogScene,
  InventoryScene,
  AlchemyScene,
  FurnitureUpgradeScene,
  BookshelfArchiveScene,
  SaveLoadScene,
  PlayerNameScene
];

